jQuery(document).ready(function(){var variations_form=jQuery(wpfactory_wc_ean_variations_obj.variations_form);if(jQuery('body').hasClass('single-product')&&variations_form.length>0){var ean=variations_form.closest(wpfactory_wc_ean_variations_obj.variations_form_closest).find('.ean');if(ean.length>0){var ean_reset=ean.text();var ean_parent=ean.parent();wpfactory_wc_ean_maybe_hide();wpfactory_wc_ean_variations()}}function wpfactory_wc_ean_variations(){variations_form.on('found_variation',function(event,variation){if(variation.ean){wpfactory_wc_ean_show(variation)}else{wpfactory_wc_ean_reset()}});variations_form.on('reset_data',wpfactory_wc_ean_reset)}function wpfactory_wc_ean_show(variation){if(variation.ean){ean.text(variation.ean);ean_parent.show()}}function wpfactory_wc_ean_reset(){if(ean_reset!==ean.text()){ean.text(ean_reset)}wpfactory_wc_ean_maybe_hide()}function wpfactory_wc_ean_maybe_hide(){if(''==ean_reset){ean_parent.hide()}}});